            <a href={SHARED_FOLDER} target="_blank" rel="noopener noreferrer"
              className="flex items-center gap-1.5 text-xs font-bold text-white px-3 py-2 rounded-xl bg-amber-500 hover:bg-amber-600 transition-colors">
              <ExternalLink size={13}/> פתח תיקיית SharePoint
            </a>
